<template><section><el-card shadow="never"><template #header><div class="bar"><b>授权书单</b><el-button type="primary" @click="collect">采集元数据书单</el-button></div></template>
<el-form inline><el-form-item><el-input v-model="q.keyword" placeholder="书名/作者/来源书号" clearable/></el-form-item><el-form-item><el-input v-model="q.sourceCode" placeholder="来源" clearable/></el-form-item><el-form-item v-for="f in filters" :key="f.key"><el-select v-model="q[f.key]" :placeholder="f.label" clearable><el-option v-for="x in f.values" :key="x" :value="x"/></el-select></el-form-item><el-button type="primary" @click="load(1)">查询</el-button></el-form>
<el-table :data="rows" v-loading="loading" @selection-change="selected=$event"><el-table-column type="selection" width="44"/><el-table-column prop="title" label="书名" min-width="150"/><el-table-column prop="author" label="作者"/><el-table-column prop="sourceCode" label="来源" width="170"/><el-table-column prop="authorizationStatus" label="授权"/><el-table-column prop="reviewStatus" label="审核"/><el-table-column prop="riskLevel" label="风险"/><el-table-column label="权限" min-width="220"><template #default="{row}">正文 {{yn(row.allowCrawlChapters)}} / 存储 {{yn(row.allowStore)}} / 展示 {{yn(row.allowDisplay)}} / VIP {{yn(row.allowVipDisplay)}}</template></el-table-column><el-table-column label="操作"><template #default="{row}"><el-button link type="primary" @click="open(row.id)">详情</el-button></template></el-table-column></el-table>
<div class="bar bottom"><span><el-button type="success" :disabled="!selected.length" @click="batch('AUTHORIZED','APPROVED')">批量授权</el-button><el-button type="danger" :disabled="!selected.length" @click="batch('REJECTED','REJECTED')">批量驳回</el-button></span><el-pagination v-model:current-page="q.page" :total="total" layout="total,prev,pager,next" @current-change="load"/></div></el-card>
<el-drawer v-model="visible" size="65%" title="授权书详情"><template v-if="detail.book"><el-descriptions :column="2" border><el-descriptions-item label="书名">{{detail.book.title}}</el-descriptions-item><el-descriptions-item label="作者">{{detail.book.author}}</el-descriptions-item><el-descriptions-item label="来源地址">{{detail.book.bookUrl}}</el-descriptions-item><el-descriptions-item label="授权证明">{{detail.book.proofRef||'-'}}</el-descriptions-item><el-descriptions-item label="元数据" :span="2">分类：{{detail.book.categoryName||'-'}}；标签：{{detail.book.tagsJson||'-'}}；简介：{{detail.book.intro||'-'}}</el-descriptions-item><el-descriptions-item label="风险原因" :span="2">{{detail.book.riskReason||'-'}}</el-descriptions-item></el-descriptions>
<el-form :model="edit" label-width="100px" class="edit"><el-form-item label="授权/审核"><el-select v-model="edit.authorizationStatus"><el-option v-for="x in filters[0].values" :key="x" :value="x"/></el-select><el-select v-model="edit.reviewStatus"><el-option v-for="x in filters[1].values" :key="x" :value="x"/></el-select></el-form-item><el-form-item label="风险"><el-select v-model="edit.riskLevel"><el-option v-for="x in filters[2].values" :key="x" :value="x"/></el-select><el-input v-model="edit.riskReason" placeholder="风险原因"/></el-form-item><el-form-item label="权限"><el-checkbox v-model="edit.allowCrawlChapters">采正文</el-checkbox><el-checkbox v-model="edit.allowStore">存储</el-checkbox><el-checkbox v-model="edit.allowDisplay">展示</el-checkbox><el-checkbox v-model="edit.allowVipDisplay">VIP 展示</el-checkbox></el-form-item><el-form-item label="证明引用"><el-input v-model="edit.proofRef"/></el-form-item><el-form-item label="备注"><el-input v-model="edit.remark" type="textarea"/></el-form-item><el-button type="primary" @click="save">确认保存</el-button></el-form><h3>审计记录</h3><el-table :data="detail.audits"><el-table-column prop="createdAt" label="时间"/><el-table-column prop="operatorId" label="操作人"/><el-table-column prop="action" label="动作"/><el-table-column prop="remark" label="备注"/><el-table-column prop="beforeJson" label="变更前" show-overflow-tooltip/><el-table-column prop="afterJson" label="变更后" show-overflow-tooltip/></el-table></template></el-drawer></section></template>
<script setup>import{onMounted,reactive,ref}from'vue';import{ElMessage,ElMessageBox}from'element-plus';import{crawlerApi}from'../services/http';
const filters=[{key:'authorizationStatus',label:'授权状态',values:['PENDING','AUTHORIZED','REJECTED']},{key:'reviewStatus',label:'审核状态',values:['PENDING','APPROVED','REJECTED']},{key:'riskLevel',label:'风险等级',values:['LOW','MEDIUM','HIGH','BLOCKED']}],q=reactive({page:1,size:20,keyword:'',sourceCode:'',authorizationStatus:'',reviewStatus:'',riskLevel:''}),rows=ref([]),total=ref(0),loading=ref(false),selected=ref([]),visible=ref(false),detail=reactive({book:null,audits:[]}),edit=reactive({}),yn=v=>v?'开':'关';
async function load(p){q.page=p||q.page;loading.value=true;try{const d=await crawlerApi.get('/authorized-books',{params:q});rows.value=d.records;total.value=d.total}finally{loading.value=false}}async function open(id){Object.assign(detail,await crawlerApi.get(`/authorized-books/${id}`));Object.assign(edit,detail.book,{remark:''});visible.value=true}async function save(){await ElMessageBox.confirm('确认保存并写入审计记录？','确认操作',{type:'warning'});await crawlerApi.put(`/authorized-books/${detail.book.id}`,{...edit,action:'ADMIN_UPDATE'});ElMessage.success('保存成功');await open(detail.book.id);await load()}async function batch(a,r){await ElMessageBox.confirm(`确认批量操作 ${selected.value.length} 本书？`,'批量操作',{type:'warning'});await crawlerApi.post('/authorized-books/batch',{ids:selected.value.map(x=>x.id),change:{authorizationStatus:a,reviewStatus:r,action:'BATCH_REVIEW',remark:'后台批量操作'}});ElMessage.success('批量操作成功');await load()}async function collect(){await ElMessageBox.confirm('仅触发元数据入口，不采集全站正文。确认？','采集元数据',{type:'warning'});await crawlerApi.post('/authorized-books/collect-metadata')}onMounted(()=>load(1));</script>
<style scoped>.bar{display:flex;justify-content:space-between;align-items:center}.bottom{margin-top:18px}.edit{margin-top:20px}.edit .el-select{margin-right:10px}</style>
